# Exemplos de Código (Atributos do Personagem)

Esta página contém implementações de referência para trabalhar com o sistema OE14CharacterStats.

## Adicionando um Modificador de Atributo a partir de uma Magia


// No seu sistema de magia
private void ApplySpellStatBonus(EntityUid target, int intBonus)
{
    if (!TryComp(target, out var stats))
        return;

    // Adiciona modificador
    stats.IntModifiers[ModifierSource.Spell] =
        stats.IntModifiers.GetValueOrDefault(ModifierSource.Spell) + intBonus;

    // Recalcula e sincroniza
    _statsSystem.RecalculateStats(target, stats);
}


## Lendo Atributos Efetivos


// Verifica se jogador atende requisito de atributo
private bool HasEnoughIntelligence(EntityUid player, int required)
{
    if (!TryComp(player, out var stats))
        return false;

    return stats.EffectiveIntelligence >= required;
}


## Removendo um Modificador


// Quando efeito de magia termina
private void RemoveSpellBonus(EntityUid target)
{
    if (!TryComp(target, out var stats))
        return;

    stats.IntModifiers.Remove(ModifierSource.Spell);
    _statsSystem.RecalculateStats(target, stats);
}


